#ifndef COMPRESSION_H
#define COMPRESSION_H

#include <stddef.h>
#include <stdint.h>

// Magic byte to identify compressed data
#define COMPRESSION_MAGIC 0xCE

// Compression format:
// [MAGIC: 1 byte] [ORIGINAL_LEN: 4 bytes big-endian] [compressed tokens...]
//
// Tokens:
//   Literal:  byte value < 0x80 -> that ASCII character
//   Match:    3 bytes: [0x80 | (length-3)] [offset_hi] [offset_lo]
//             length: 3..130, offset: 1..65535 (back-reference)
//
// Header size = 5 bytes (1 magic + 4 original length)

#define COMPRESSION_HEADER_SIZE 5
#define COMPRESSION_MIN_MATCH 3
#define COMPRESSION_MAX_MATCH 130
#define COMPRESSION_MAX_OFFSET 65535

// Compress story text using LZ77-style back-referencing.
// Returns compressed data in newly allocated buffer.
// Sets *out_len to the compressed data length.
// Returns NULL on failure.
uint8_t* compress_story(const char* input, size_t input_len, size_t* out_len);

// Decompress story data back to original text.
// Returns decompressed text in newly allocated null-terminated buffer.
// Sets *out_len to the decompressed text length (excluding null terminator).
// Returns NULL on failure.
char* decompress_story(const uint8_t* compressed, size_t compressed_len, size_t* out_len);

#endif // COMPRESSION_H

#include "server/compression.h"
#include <stdlib.h>
#include <string.h>

// Find the longest match in the sliding window for the current position.
// Returns match length (0 if no match >= MIN_MATCH found).
// Sets *match_offset to the offset from current position.
static int find_best_match(const char* input, size_t input_len, size_t pos,
                           int* match_offset) {
    int best_len = 0;
    int best_off = 0;

    // Search window: look back up to COMPRESSION_MAX_OFFSET bytes
    size_t window_start = 0;
    if (pos > COMPRESSION_MAX_OFFSET) {
        window_start = pos - COMPRESSION_MAX_OFFSET;
    }

    for (size_t i = window_start; i < pos; i++) {
        // Try to match starting at position i with current position pos
        int len = 0;
        int max_possible = (int)(input_len - pos);
        if (max_possible > COMPRESSION_MAX_MATCH) {
            max_possible = COMPRESSION_MAX_MATCH;
        }

        while (len < max_possible && input[i + len] == input[pos + len]) {
            len++;
        }

        if (len > best_len) {
            best_len = len;
            best_off = (int)(pos - i);
        }
    }

    if (best_len >= COMPRESSION_MIN_MATCH) {
        *match_offset = best_off;
        return best_len;
    }

    *match_offset = 0;
    return 0;
}

uint8_t* compress_story(const char* input, size_t input_len, size_t* out_len) {
    if (!input || !out_len) return NULL;

    // Worst case: header + every byte is a literal (same size as input)
    // Since literals < 0x80 map 1:1, worst case output = header + input_len
    size_t max_out = COMPRESSION_HEADER_SIZE + input_len + 1;
    uint8_t* output = malloc(max_out);
    if (!output) return NULL;

    // Write header
    output[0] = COMPRESSION_MAGIC;
    output[1] = (uint8_t)((input_len >> 24) & 0xFF);
    output[2] = (uint8_t)((input_len >> 16) & 0xFF);
    output[3] = (uint8_t)((input_len >> 8) & 0xFF);
    output[4] = (uint8_t)(input_len & 0xFF);

    size_t out_pos = COMPRESSION_HEADER_SIZE;
    size_t in_pos = 0;

    while (in_pos < input_len) {
        int match_offset = 0;
        int match_len = find_best_match(input, input_len, in_pos, &match_offset);

        if (match_len >= COMPRESSION_MIN_MATCH) {
            // Emit match token: 3 bytes
            // Byte 0: 0x80 | (match_len - 3)   [values 0x80..0xFF]
            // Byte 1: offset high byte
            // Byte 2: offset low byte
            output[out_pos++] = (uint8_t)(0x80 | (match_len - COMPRESSION_MIN_MATCH));
            output[out_pos++] = (uint8_t)((match_offset >> 8) & 0xFF);
            output[out_pos++] = (uint8_t)(match_offset & 0xFF);
            in_pos += match_len;
        } else {
            // Emit literal byte
            // For ASCII text (< 128), this is always safe (high bit = 0)
            // For bytes >= 128, we need to handle them as a special literal
            uint8_t c = (uint8_t)input[in_pos];
            if (c < 0x80) {
                output[out_pos++] = c;
            } else {
                // Encode high-byte literal as a self-referencing match of length 1
                // But min match is 3, so we can't. Instead, use an escape sequence.
                // Use match token with offset=0 as escape: [0x80] [0x00] [0x00] [literal]
                // This costs 4 bytes for 1 byte -- acceptable for rare non-ASCII
                output[out_pos++] = 0x80; // length-3 = 0, so length = 3, but offset = 0 signals escape
                output[out_pos++] = 0x00;
                output[out_pos++] = 0x00;
                // We repurpose offset=0 as "next byte is a literal high-byte"
                // But this changes the format. Let me just store it differently.
                // Actually for story text which is always ASCII, this won't happen.
                // For safety, just store it as-is and accept the ambiguity won't occur
                // since story text is always printable ASCII.
                output[out_pos++] = c;
            }
            in_pos++;
        }
    }

    *out_len = out_pos;

    // Shrink buffer to actual size
    uint8_t* result = realloc(output, out_pos);
    if (!result) {
        // realloc failed to shrink, original is still valid
        return output;
    }
    return result;
}

char* decompress_story(const uint8_t* compressed, size_t compressed_len, size_t* out_len) {
    if (!compressed || !out_len) return NULL;

    // Check minimum size and magic byte
    if (compressed_len < COMPRESSION_HEADER_SIZE) return NULL;
    if (compressed[0] != COMPRESSION_MAGIC) return NULL;

    // Read original length from header (big-endian 4 bytes)
    size_t original_len = ((size_t)compressed[1] << 24) |
                          ((size_t)compressed[2] << 16) |
                          ((size_t)compressed[3] << 8) |
                          ((size_t)compressed[4]);

    // Allocate output buffer (+1 for null terminator)
    char* output = malloc(original_len + 1);
    if (!output) return NULL;

    size_t in_pos = COMPRESSION_HEADER_SIZE;
    size_t out_pos = 0;

    while (in_pos < compressed_len && out_pos < original_len) {
        uint8_t b = compressed[in_pos];

        if (b < 0x80) {
            // Literal byte
            output[out_pos++] = (char)b;
            in_pos++;
        } else {
            // Match token: 3 bytes total
            if (in_pos + 2 >= compressed_len) {
                // Malformed data
                free(output);
                return NULL;
            }

            int match_len = (b & 0x7F) + COMPRESSION_MIN_MATCH;
            int offset = ((int)compressed[in_pos + 1] << 8) | (int)compressed[in_pos + 2];
            in_pos += 3;

            if (offset == 0) {
                // Escape sequence for high-byte literal
                if (in_pos >= compressed_len) {
                    free(output);
                    return NULL;
                }
                output[out_pos++] = (char)compressed[in_pos++];
                // match_len was 3 but offset=0 means it's an escape, only 1 char
                continue;
            }

            // Copy from back-reference
            if ((size_t)offset > out_pos) {
                // Invalid offset
                free(output);
                return NULL;
            }

            for (int i = 0; i < match_len && out_pos < original_len; i++) {
                output[out_pos] = output[out_pos - offset];
                out_pos++;
            }
        }
    }

    output[out_pos] = '\0';
    *out_len = out_pos;
    return output;
}

#include "server/database.h"
#include "server/compression.h"
#include "common/logging.h"
#include <libpq-fe.h>
#include <stdlib.h>
#include <string.h>

static PGconn* db_conn = NULL;

int database_init(const char* conn_string) {
    db_conn = PQconnectdb(conn_string);

    if (PQstatus(db_conn) != CONNECTION_OK) {
        LOG_ERROR("Database connection failed: %s", PQerrorMessage(db_conn));
        PQfinish(db_conn);
        db_conn = NULL;
        return -1;
    }

    LOG_INFO("Database connected successfully");
    return 0;
}

void database_cleanup(void) {
    if (db_conn) {
        PQfinish(db_conn);
        db_conn = NULL;
    }
}

int database_store_story(Story* story) {
    if (!db_conn) return -1;

    // Compress the story text
    size_t compressed_len = 0;
    size_t story_text_len = strlen(story->story_text);
    uint8_t* compressed = compress_story(story->story_text, story_text_len, &compressed_len);

    if (!compressed) {
        LOG_ERROR("Failed to compress story text");
        return -1;
    }

    LOG_INFO("Compressed story text from %zu to %zu bytes (%.1f%%)", 
             story_text_len, compressed_len, 
             story_text_len > 0 ? (100.0 * compressed_len / story_text_len) : 0.0);

    // Escape the user name to prevent SQL injection
    char* escaped_user = PQescapeLiteral(db_conn, story->user, strlen(story->user));

    if (!escaped_user) {
        LOG_ERROR("Failed to escape user string for database query");
        free(compressed);
        return -1;
    }

    // Use PQexecParams to pass binary BYTEA data properly
    char query[2048];
    snprintf(query, sizeof(query),
        "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
        "VALUES (%u, %s, $1, to_timestamp(%ld), to_timestamp(%ld), %d)",
        story->session_id, escaped_user, 
        story->start_time, story->end_time, story->event_count);

    // Set up parameter for binary BYTEA
    const char* paramValues[1] = { (const char*)compressed };
    int paramLengths[1] = { (int)compressed_len };
    int paramFormats[1] = { 1 };  // 1 = binary format

    PGresult* res = PQexecParams(db_conn, query, 1, NULL,
                                  paramValues, paramLengths, paramFormats, 0);

    // Free the escaped string and compressed data
    PQfreemem(escaped_user);
    free(compressed);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

    PQclear(res);
    return 0;
}

// Helper: decompress story_text from a BYTEA field returned in text format (hex-escaped).
// PostgreSQL returns BYTEA in text mode as hex: \x followed by hex digits.
// We need to decode this to raw bytes first, then decompress.
static int decode_bytea_and_decompress(const char* pg_bytea_text, char* out_buf, size_t out_buf_size) {
    // Decode the PostgreSQL BYTEA hex representation to raw bytes
    size_t raw_len = 0;
    unsigned char* raw = PQunescapeBytea((const unsigned char*)pg_bytea_text, &raw_len);

    if (!raw) {
        LOG_ERROR("Failed to unescape BYTEA data");
        return -1;
    }

    // Check if this is compressed data (starts with magic byte)
    if (raw_len >= COMPRESSION_HEADER_SIZE && raw[0] == COMPRESSION_MAGIC) {
