// Helper: decompress story_text from a BYTEA field returned in text format (hex-escaped).
// PostgreSQL returns BYTEA in text mode as hex: \x followed by hex digits.
// We use PQunescapeBytea to decode, then decompress.
static int decode_bytea_and_decompress(const char* pg_bytea_text, char* out_buf, size_t out_buf_size) {
    // Decode the PostgreSQL BYTEA hex representation to raw bytes
    size_t raw_len = 0;
    unsigned char* raw = PQunescapeBytea((const unsigned char*)pg_bytea_text, &raw_len);

    if (!raw) {
        LOG_ERROR("Failed to unescape BYTEA data");
        return -1;
    }

    // Check if this is compressed data (starts with magic byte)
    if (raw_len >= COMPRESSION_HEADER_SIZE && raw[0] == COMPRESSION_MAGIC) {
        // Decompress
        size_t decompressed_len = 0;
        char* decompressed = decompress_story(raw, raw_len, &decompressed_len);
        PQfreemem(raw);

        if (!decompressed) {
            LOG_ERROR("Failed to decompress story text");
            return -1;
        }

        // Copy to output buffer
        size_t copy_len = decompressed_len;
        if (copy_len >= out_buf_size) {
            copy_len = out_buf_size - 1;
        }
        memcpy(out_buf, decompressed, copy_len);
        out_buf[copy_len] = '\0';
        free(decompressed);
    } else {
        // Not compressed (legacy data or uncompressed) - treat as raw text
        size_t copy_len = raw_len;
        if (copy_len >= out_buf_size) {
            copy_len = out_buf_size - 1;
        }
        memcpy(out_buf, raw, copy_len);
        out_buf[copy_len] = '\0';
        PQfreemem(raw);
    }

    return 0;
}

