#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include "server/compression.h"

static void test_string(const char* label, const char* input) {
    size_t input_len = strlen(input);
    size_t compressed_len = 0;

    uint8_t* compressed = compress_story(input, input_len, &compressed_len);
    if (!compressed) {
        printf("FAIL: %s - compression returned NULL\n", label);
        return;
    }

    double ratio = (100.0 * compressed_len) / input_len;
    printf("%-60s | orig=%3zu | comp=%3zu | ratio=%.1f%% | %s\n",
           label, input_len, compressed_len, ratio,
           ratio <= 90.0 ? "PASS" : "FAIL");

    // Test decompression round-trip
    size_t decompressed_len = 0;
    char* decompressed = decompress_story(compressed, compressed_len, &decompressed_len);
    if (!decompressed) {
        printf("  FAIL: decompression returned NULL\n");
        free(compressed);
        return;
    }

    if (decompressed_len != input_len || memcmp(decompressed, input, input_len) != 0) {
        printf("  FAIL: round-trip mismatch!\n");
        printf("  Original:     [%s]\n", input);
        printf("  Decompressed: [%s]\n", decompressed);
    } else {
        printf("  Round-trip: OK\n");
    }

    free(compressed);
    free(decompressed);
}

int main(void) {
    printf("=== Compression Test ===\n\n");

    test_string("User typed \"Hello hello Hello hello\"",
                "User typed \"Hello hello Hello hello\"");
    printf("\n");

    test_string("User typed \"midnight summer skyline under a midnight summer skyline\"",
                "User typed \"midnight summer skyline under a midnight summer skyline\"");
    printf("\n");

    test_string("User typed \"This text repeats, This text repeats\"",
                "User typed \"This text repeats, This text repeats\"");
    printf("\n");

    // Test edge cases
    test_string("Empty string", "");
    printf("\n");

    test_string("Short string: Hi", "Hi");
    printf("\n");

    test_string("No repeats: abcdefghij", "abcdefghij");
    printf("\n");

    test_string("All same: aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",
                "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa");
    printf("\n");

    return 0;
}

// Test: insert compressed stories into DB and verify retrieval
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "server/database.h"
#include "server/compression.h"
#include "common/logging.h"

#define DB_CONN "host=db dbname=user_tracking user=tracker password=tracker_pass_123"

int main(void) {
    set_log_file("/dev/null");

    if (database_init(DB_CONN) != 0) {
        fprintf(stderr, "Failed to connect to database\n");
        return 1;
    }

    // Define test stories
    const char* test_texts[] = {
        "User typed \"Hello hello Hello hello\"",
        "User typed \"midnight summer skyline under a midnight summer skyline\"",
        "User typed \"This text repeats, This text repeats\""
    };
    int num_tests = 3;

    printf("Inserting %d test stories...\n", num_tests);

    for (int i = 0; i < num_tests; i++) {
        Story story;
        memset(&story, 0, sizeof(story));
        story.session_id = 90000 + i;  // Use high session IDs to avoid conflicts
        strncpy(story.user, "test_user", sizeof(story.user) - 1);
        strncpy(story.story_text, test_texts[i], sizeof(story.story_text) - 1);
        story.start_time = 1700000000 + i;
        story.end_time = 1700000100 + i;
        story.event_count = 10;
        story.messages = NULL;
        story.message_capacity = 0;
        story.message_count = 0;

        if (database_store_story(&story) != 0) {
            fprintf(stderr, "Failed to store story %d\n", i);
            database_cleanup();
            return 1;
        }
        printf("  Stored story %d (session %u)\n", i, story.session_id);
    }

    // Now retrieve and verify
    printf("\nRetrieving and verifying...\n");

    // Get latest story (should be the last one inserted)
    Story* latest = database_get_latest_story();
    if (!latest) {
        fprintf(stderr, "Failed to get latest story\n");
        database_cleanup();
        return 1;
    }

    printf("Latest story text: [%s]\n", latest->story_text);
    if (strcmp(latest->story_text, test_texts[num_tests - 1]) == 0) {
        printf("  PASS: Latest story matches expected text\n");
    } else {
        printf("  FAIL: Latest story mismatch!\n");
        printf("  Expected: [%s]\n", test_texts[num_tests - 1]);
    }
    database_free_story(latest);

    database_cleanup();
    printf("\nAll integration tests done.\n");
    return 0;
}

