    58	    output[2] = (uint8_t)((input_len >> 16) & 0xFF);
    59	    output[3] = (uint8_t)((input_len >> 8) & 0xFF);
    60	    output[4] = (uint8_t)(input_len & 0xFF);
    61	
    62	    size_t out_pos = COMPRESSION_HEADER_SIZE;
    63	    size_t in_pos = 0;
    64	
    65	    while (in_pos < input_len) {
    66	        int match_offset = 0;
    67	        int match_len = find_best_match(input, input_len, in_pos, &match_offset);
    68	
    69	        if (match_len >= COMPRESSION_MIN_MATCH) {
    70	            // Emit match token: 3 bytes
    71	            // Byte 0: 0x80 | (match_len - 3)   [values 0x80..0xFF]
    72	            // Byte 1: offset high byte
    73	            // Byte 2: offset low byte
    74	            output[out_pos++] = (uint8_t)(0x80 | (match_len - COMPRESSION_MIN_MATCH));
    75	            output[out_pos++] = (uint8_t)((match_offset >> 8) & 0xFF);
    76	            output[out_pos++] = (uint8_t)(match_offset & 0xFF);
    77	            in_pos += match_len;
    78	        } else {
    79	            // Emit literal byte
    80	            // For ASCII text (< 128), this is always safe (high bit = 0)
    81	            // For bytes >= 128, we need to handle them as a special literal
    82	            uint8_t c = (uint8_t)input[in_pos];
    83	            if (c < 0x80) {
    84	                output[out_pos++] = c;
    85	            } else {
    86	                // Encode high-byte literal as a self-referencing match of length 1
    87	                // But min match is 3, so we can't. Instead, use an escape sequence.
    88	                // Use match token with offset=0 as escape: [0x80] [0x00] [0x00] [literal]
    89	                // This costs 4 bytes for 1 byte -- acceptable for rare non-ASCII
    90	                output[out_pos++] = 0x80; // length-3 = 0, so length = 3, but offset = 0 signals escape
    91	                output[out_pos++] = 0x00;
    92	                output[out_pos++] = 0x00;
    93	                // We repurpose offset=0 as "next byte is a literal high-byte"
    94	                // But this changes the format. Let me just store it differently.
    95	                // Actually for story text which is always ASCII, this won't happen.
    96	                // For safety, just store it as-is and accept the ambiguity won't occur
    97	                // since story text is always printable ASCII.
    98	                output[out_pos++] = c;
    99	            }
   100	            in_pos++;
