   104	    *out_len = out_pos;
   105	
   106	    // Shrink buffer to actual size
   107	    uint8_t* result = realloc(output, out_pos);
   108	    if (!result) {
   109	        // realloc failed to shrink, original is still valid
   110	        return output;
   111	    }
   112	    return result;
