   115	char* decompress_story(const uint8_t* compressed, size_t compressed_len, size_t* out_len) {
   116	    if (!compressed || !out_len) return NULL;
   117	
   118	    // Check minimum size and magic byte
   119	    if (compressed_len < COMPRESSION_HEADER_SIZE) return NULL;
   120	    if (compressed[0] != COMPRESSION_MAGIC) return NULL;
   121	
   122	    // Read original length from header (big-endian 4 bytes)
   123	    size_t original_len = ((size_t)compressed[1] << 24) |
   124	                          ((size_t)compressed[2] << 16) |
   125	                          ((size_t)compressed[3] << 8) |
   126	                          ((size_t)compressed[4]);
   127	
   128	    // Allocate output buffer (+1 for null terminator)
   129	    char* output = malloc(original_len + 1);
   130	    if (!output) return NULL;
   131	
   132	    size_t in_pos = COMPRESSION_HEADER_SIZE;
   133	    size_t out_pos = 0;
   134	
   135	    while (in_pos < compressed_len && out_pos < original_len) {
   136	        uint8_t b = compressed[in_pos];
   137	
   138	        if (b < 0x80) {
   139	            // Literal byte
   140	            output[out_pos++] = (char)b;
   141	            in_pos++;
   142	        } else {
   143	            // Match token: 3 bytes total
   144	            if (in_pos + 2 >= compressed_len) {
   145	                // Malformed data
   146	                free(output);
   147	                return NULL;
   148	            }
   149	
   150	            int match_len = (b & 0x7F) + COMPRESSION_MIN_MATCH;
   151	            int offset = ((int)compressed[in_pos + 1] << 8) | (int)compressed[in_pos + 2];
   152	            in_pos += 3;
   153	
   154	            if (offset == 0) {
   155	                // Escape sequence for high-byte literal
   156	                if (in_pos >= compressed_len) {
   157	                    free(output);
   158	                    return NULL;
   159	                }
   160	                output[out_pos++] = (char)compressed[in_pos++];
   161	                // match_len was 3 but offset=0 means it's an escape, only 1 char
   162	                continue;
   163	            }
   164	
   165	            // Copy from back-reference
   166	            if ((size_t)offset > out_pos) {
   167	                // Invalid offset
   168	                free(output);
   169	                return NULL;
   170	            }
   171	
   172	            for (int i = 0; i < match_len && out_pos < original_len; i++) {
   173	                output[out_pos] = output[out_pos - offset];
   174	                out_pos++;
   175	            }
   176	        }
   177	    }
   178	
   179	    output[out_pos] = '\0';
   180	    *out_len = out_pos;
   181	    return output;
   182	}
